import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { Eye, EyeOff, Lock, Building2, User, AlertCircle, Loader2 } from 'lucide-react';

function Login({ onLoginSuccess }) {
  const [username, setUsername] = useState('');
  const [company, setCompany] = useState('EMIN');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Logo base64 obtenido de la versión original
  const eminLogo = "data:image/png;base64,";

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const { data, error } = await supabase
        .from('usuarios')
        .select('*')
        .eq('usuario', username.trim())
        .eq('empresa', company.trim())
        .eq('contrasena', password.trim())
        .maybeSingle();

      if (error) {
        throw new Error('Error al conectar con la base de datos: ' + error.message);
      }

      if (!data) {
        setError('Credenciales incorrectas o empresa no registrada.');
        setLoading(false);
        return;
      }

      // Login exitoso, guardamos el usuario en local y notificamos a App.jsx
      onLoginSuccess(data);
    } catch (err) {
      setError(err.message || 'Ocurrió un error inesperado al intentar iniciar sesión.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4 bg-gradient-to-tr from-blue-950 via-indigo-950 to-slate-950">
      <div className="bg-white p-8 rounded-2xl shadow-2xl max-w-sm w-full border border-slate-100/20">
        
        {/* Encabezado y Logo */}
        <div className="text-center mb-6">
          <img src={eminLogo} className="mx-auto w-44 mb-3" alt="EMIN Logo" />
          <h2 className="text-xl font-bold text-slate-800">Portal de Proyectos</h2>
          <p className="text-xs text-slate-500 mt-1 font-medium">Control Operativo Centralizado</p>
        </div>

        {/* Mensaje de Error */}
        {error && (
          <div className="bg-red-50 border border-red-200 text-red-700 p-3 rounded-lg flex items-start gap-2 mb-4 text-xs font-medium animate-shake">
            <AlertCircle className="w-4 h-4 mt-0.5 shrink-0" />
            <span>{error}</span>
          </div>
        )}

        {/* Formulario */}
        <form onSubmit={handleLogin} className="space-y-4">
          
          {/* Usuario */}
          <div>
            <label className="block text-[10px] font-bold uppercase tracking-wider text-slate-500 mb-1">
              Usuario
            </label>
            <div className="relative">
              <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400">
                <User className="w-4 h-4" />
              </span>
              <input
                type="text"
                required
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder="Ingresa tu usuario"
                className="pl-9 text-slate-800 font-medium w-full px-3 py-2.5 border rounded-lg border-slate-200 focus:outline-none focus:border-blue-600 focus:ring-1 focus:ring-blue-600 transition text-sm bg-slate-50"
              />
            </div>
          </div>

          {/* Empresa */}
          <div>
            <label className="block text-[10px] font-bold uppercase tracking-wider text-slate-500 mb-1">
              Empresa
            </label>
            <div className="relative">
              <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400">
                <Building2 className="w-4 h-4" />
              </span>
              <input
                type="text"
                required
                value={company}
                onChange={(e) => setCompany(e.target.value)}
                placeholder="Compañía"
                className="pl-9 text-slate-800 font-medium w-full px-3 py-2.5 border rounded-lg border-slate-200 focus:outline-none focus:border-blue-600 focus:ring-1 focus:ring-blue-600 transition text-sm bg-slate-50"
              />
            </div>
          </div>

          {/* Contraseña */}
          <div>
            <label className="block text-[10px] font-bold uppercase tracking-wider text-slate-500 mb-1">
              Contraseña
            </label>
            <div className="relative">
              <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400">
                <Lock className="w-4 h-4" />
              </span>
              <input
                type={showPassword ? "text" : "password"}
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                className="pl-9 pr-10 text-slate-800 font-medium w-full px-3 py-2.5 border rounded-lg border-slate-200 focus:outline-none focus:border-blue-600 focus:ring-1 focus:ring-blue-600 transition text-sm bg-slate-50"
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600"
              >
                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          </div>

          {/* Botón de Ingreso */}
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-blue-900 hover:bg-blue-800 text-white font-semibold py-3 rounded-lg shadow-md hover:-translate-y-0.5 transition active:translate-y-0 text-sm flex items-center justify-center gap-2 cursor-pointer disabled:opacity-75 disabled:pointer-events-none"
          >
            {loading ? (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                <span>Validando...</span>
              </>
            ) : (
              <span>Ingresar al Portal</span>
            )}
          </button>

        </form>

      </div>
    </div>
  );
}

export default Login;
